# Example Python code for a simple Roman numeral converter
def roman_to_decimal(roman_numeral):
  roman_numerals = {'M': 1000, 'D': 500, 'C': 100, 'L': 50, 'X': 10, 'V': 5, 'I': 1}
  decimal = 0
  for char in roman_numeral:
    decimal += roman_numerals[char]
  return decimal

print(roman_to_decimal('MMXXVI'))  # Output: 2026
